# platform_auth/deprecated.py — deprecation utility for library code
import warnings
from functools import wraps
from typing import Callable, Optional

def deprecated(since: str, removed_in: str, use_instead: Optional[str] = None):
    """Decorator to mark a function as deprecated with version context."""
    def decorator(func: Callable) -> Callable:
        msg = (
            f"{func.__name__} is deprecated since {since} and will be "
            f"removed in {removed_in}."
        )
        if use_instead:
            msg += f" Use {use_instead} instead."

        @wraps(func)
        def wrapper(*args, **kwargs):
            warnings.warn(msg, DeprecationWarning, stacklevel=2)
            return func(*args, **kwargs)

        wrapper.__doc__ = f"[DEPRECATED since {since}, removed in {removed_in}] " + (
            func.__doc__ or ""
        )
        return wrapper
    return decorator

# Usage in library code:
# @deprecated(since="1.2.0", removed_in="2.0.0", use_instead="validate_jwt_v2")
# def validate_token(token: str) -> dict:
#     ...  # old implementation, delegates to new one
